e last 3 days. Tanker supply is irregular. Authorities must resolve this immediately.', NULL, 1, 2, NULL, 'madurai', true, 'மதுரை வட மாவட்ட மக்களுக்கு கடந்த 3 நாட்களாக குழாய் தண்ணீர் விநியோகம் இல்லை.', NULL, 'hidden', NULL, 'Water supply disruption in Madurai North for 3 days', 'மதுரை வடக்கில் 3 நாட்களாக குடிநீர் விரவில் இடைஞ்சல்', 'water-sanitation', '[]'::jsonb, 'removed', '6a0ffb09ad8e8cc9b79b304d', '2026-05-22T06:43:21.610000', '2026-06-03T16:35:40.523000', '6a056bc4-3e85-a088-a136-e18100000000', 'divyak252026@gmail.com', false) ON CONFLICT (id) DO NOTHING;
INSERT INTO "post" ("area_name", "author_name", "comment_count", "duplicate_count", "citizen_fixed_count", "category_name", "timeline_events", "before_photos", "upvotes", "urgency_level", "district_name", "final_resolution_photos", "complaint_filed_date", "complaint_link", "civic_status", "post_type", "still_not_fixed_count", "claimed_fixed_photos", "area_slug", "escalation_level", "location_text", "official_complaint_id", "is_publicly_visible", "admin_note", "is_community_solved", "content_en", "civic_receipt_id", "downvotes", "verification_count", "assigned_department", "district_slug", "is_anonymous", "content_ta", "complaint_notes", "moderation_status", "complaint_screenshot_url", "title_en", "title_ta", "category_slug", "media_urls", "status", "id", "created_date", "updated_date", "created_by_id", "created_by", "is_sample") VALUES (NULL, NULL, 15, NULL, NULL, 'Transport', NULL, NULL, 78, NULL, 'Vellore', NULL, NULL, NULL, NULL, 'complaint', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'The Tamil Nadu State Transport Corporation has reduced bus frequency on the Vellore-Chennai route from 30-minute intervals to 60 minutes, causing severe inconvenience to daily commuters.', NULL, 4, NULL, NULL, 'vellore', true, 'வேலூர்-சென்னை பாதையில் பேருந்து இடைவெளி 30 நிமிடத்திலிருந்து 60 நிமிடமாக குறைக்கப்பட்டுள்ளது.', NULL, NULL, NULL, 'Bus frequency reduced on Vellore-Chennai route, commuters suffer', 'வேலூர்-சென்னை பாதையில் பேருந்து இடைவெளி குறைக்கப்பட்டது, பயணிகள் அவதி', 'transport', '[]'::jsonb, 'active', '6a0ffb09ad8e8cc9b79b3052', '2026-05-22T06:43:21.610000', '2026-05-22T06:43:21.610000', '6a056bc4-3e85-a088-a136-e18100000000', 'divyak252026@gmail.com', false) ON CONFLICT (id) DO NOTHING;
